typedef struct {uint64_t *keys; char *used; size_t cap; size_t sz;} U64Set;
static size_t next_pow2(size_t n){size_t p=1;while(p<n)p<<=1;return p;}
static U64Set* set_create(size_t expected){U64Set *s=malloc(sizeof(U64Set));s->cap=next_pow2(expected*2);s->sz=0;s->keys=calloc(s->cap,sizeof(uint64_t));s->used=calloc(s->cap,sizeof(char));return s;}
static void set_free(U64Set *s){free(s->keys);free(s->used);free(s);} 
static size_t hash_uint64(uint64_t x){return (size_t)(x ^ (x>>33));}
static bool set_contains(U64Set *s,uint64_t x){size_t idx=hash_uint64(x)&(s->cap-1);while(s->used[idx]){if(s->keys[idx]==x)return true;idx=(idx+1)&(s->cap-1);}return false;}
static void set_insert(U64Set *s,uint64_t x){if(set_contains(s,x))return;size_t idx=hash_uint64(x)&(s->cap-1);while(s->used[idx])idx=(idx+1)&(s->cap-1);s->used[idx]=1;s->keys[idx]=x;s->sz++;}
