const fs=require('fs');
const data=fs.readFileSync(0,'utf-8').trim().split(/\s+/);
let idx=0;
const T=Number(data[idx++]);
let out=[];
for(let t=0;t<T;t++){
  const N=Number(data[idx++]);
  const A=new Array(N);
  for(let i=0;i<N;i++)A[i]=BigInt(data[idx++]);
  const seen=new Set();
  let cur=[];
  let ok=true;
  for(const a of A){
    let nxt=[a];
    for(const x of cur) nxt.push(x|a);
    const uniqMap=new Map();
    for(const v of nxt) uniqMap.set(v.toString(),v);
    cur=Array.from(uniqMap.values());
    for(const v of cur){
      const key=v.toString();
      if(seen.has(key)){ok=false;break;}
      seen.add(key);
    }
    if(!ok)break;
  }
  out.push(ok?"YES":"NO");
}
console.log(out.join('\n'));
